class NavDropdown{constructor(){this.dropdowns=document.querySelectorAll(".nav-dropdown"),this.init()}init(){this.dropdowns.forEach(e=>{const t=e.querySelector(".nav-dropdown-toggle"),n=e.querySelector(".nav-dropdown-menu");t&&n&&(e.closest(".mobile-nav")||(t.addEventListener("click",t=>{t.preventDefault(),this.toggleDropdown(e)}),document.addEventListener("click",t=>{e.contains(t.target)||this.closeDropdown(e)}),t.addEventListener("keydown",t=>{t.key==="Enter"||t.key===" "?(t.preventDefault(),this.toggleDropdown(e)):t.key==="Escape"&&this.closeDropdown(e)})))})}toggleDropdown(e){const s=e.querySelector(".nav-dropdown-toggle"),t=e.querySelector(".nav-dropdown-menu"),n=t.classList.contains("show");this.closeAllDropdowns(),n||this.openDropdown(e)}openDropdown(e){const t=e.querySelector(".nav-dropdown-toggle"),n=e.querySelector(".nav-dropdown-menu");n.classList.add("show"),t.setAttribute("aria-expanded","true")}closeDropdown(e){const t=e.querySelector(".nav-dropdown-toggle"),n=e.querySelector(".nav-dropdown-menu");n.classList.remove("show"),t.setAttribute("aria-expanded","false")}closeAllDropdowns(){this.dropdowns.forEach(e=>{this.closeDropdown(e)})}}document.addEventListener("DOMContentLoaded",()=>{new NavDropdown}),window.NavDropdown=NavDropdown